/app/ars.R.content:
# Adaptive rejection sampling for log-concave one-dimensional densities.
# Reference: Gilks, W. R. and Wild, P. (1992), Applied Statistics 41(2), 337-348.

.ars_stop <- function(...) {
  stop(sprintf(...), call. = FALSE)
}

.ars_check_count <- function(n) {
  if (!is.numeric(n) || length(n) != 1L || !is.finite(n) || is.na(n)) {
    .ars_stop("n must be a single positive integer.")
  }
  if (n <= 0 || abs(n - round(n)) > .Machine$double.eps^0.5) {
    .ars_stop("n must be a single positive integer.")
  }
  as.integer(round(n))
}

.ars_check_domain <- function(domain) {
  if (!is.numeric(domain) || length(domain) != 2L || any(is.na(domain))) {
    .ars_stop("domain must be a numeric vector of length 2.")
  }
  if (domain[1L] >= domain[2L]) {
    .ars_stop("domain lower bound must be strictly less than upper bound.")
  }
  as.numeric(domain)
}

.ars_to_log <- function(value, input_length, log_density) {
  if (!is.numeric(value)) {
    .ars_stop("target density must return numeric values.")
  }
  if (length(value) != input_length) {
    .ars_stop("target density must be vectorized and return one value per input.")
  }
  if (log_density) {
    if (any(is.na(value) | is.nan(value) | value == Inf)) {
      .ars_stop("target log density returned NA, NaN, or +Inf.")
    }
    return(as.numeric(value))
  }
  if (any(is.na(value) | is.nan(value) | !is.finite(value) | value < 0)) {
    .ars_stop("target density returned NA, NaN, Inf, or negative values.")
  }
  log(as.numeric(value))
}

.ars_make_log_density <- function(target_expr, env, log_density, target_args) {
  target_value <- try(eval(target_expr, envir = env), silent = TRUE)

  if (inherits(target_value, "try-error")) {
    if (!is.call(target_expr)) {
      .ars_stop("target must be a function or an expression involving x.")
    }
    if (length(target_args) > 0L) {
      .ars_stop("additional target arguments can only be used when target is a function.")
    }
    return(function(x) {
      value <- eval(target_expr, envir = list2env(list(x = x), parent = env))
      .ars_to_log(value, length(x), log_density)
    })
  }

  if (is.function(target_value)) {
    return(function(x) {
      value <- do.call(target_value, c(list(x), target_args))
      .ars_to_log(value, length(x), log_density)
    })
  }

  if (is.expression(target_value)) {
    if (length(target_args) > 0L) {
      .ars_stop("additional target arguments can only be used when target is a function.")
    }
    if (length(target_value) != 1L) {
      .ars_stop("target expression must contain exactly one expression.")
    }
    expr <- target_value[[1L]]
    return(function(x) {
      value <- eval(expr, envir = list2env(list(x = x), parent = env))
      .ars_to_log(value, length(x), log_density)
    })
  }

  if (is.character(target_value) && length(target_value) == 1L) {
    if (length(target_args) > 0L) {
      .ars_stop("additional target arguments can only be used when target is a function.")
    }
    expr <- parse(text = target_value)[[1L]]
    return(function(x) {
      value <- eval(expr, envir = list2env(list(x = x), parent = env))
      .ars_to_log(value, length(x), log_density)
    })
  }

  .ars_stop("target must be a function or an expression involving x.")
}

.ars_default_initial_points <- function(domain) {
  lower <- domain[1L]
  upper <- domain[2L]

  if (is.finite(lower) && is.finite(upper)) {
    return(lower + c(0.25, 0.5, 0.75) * (upper - lower))
  }
  if (is.finite(lower)) {
    return(lower + c(0.25, 1, 3))
  }
  if (is.finite(upper)) {
    return(upper - c(3, 1, 0.25))
  }
  c(-1, 0, 1)
}

.ars_check_initial_points <- function(initial_points, domain) {
  if (!is.numeric(initial_points) || length(initial_points) < 1L) {
    .ars_stop("initial_points must be a numeric vector with at least one point.")
  }
  if (any(!is.finite(initial_points) | is.na(initial_points))) {
    .ars_stop("initial_points must be finite values inside the domain.")
  }
  if (any(initial_points <= domain[1L] | initial_points >= domain[2L])) {
    .ars_stop("initial_points must lie strictly inside the domain.")
  }
  sort(unique(as.numeric(initial_points)))
}

.ars_numeric_derivative_one <- function(log_f, x, domain, derivative_step) {
  step <- derivative_step
  if (is.null(step)) {
    step <- 1e-5 * (1 + abs(x))
    if (is.finite(domain[1L]) && is.finite(domain[2L])) {
      step <- min(step, (domain[2L] - domain[1L]) / 1000)
    }
  }
  if (!is.numeric(step) || length(step) != 1L || !is.finite(step) || step <= 0) {
    .ars_stop("derivative_step must be a single positive finite number.")
  }

  for (attempt in seq_len(25L)) {
    left <- x - step
    right <- x + step

    if (left > domain[1L] && right < domain[2L]) {
      h <- log_f(c(left, right))
      if (all(is.finite(h))) {
        return((h[2L] - h[1L]) / (2 * step))
      }
    } else if (right < domain[2L]) {
      h <- log_f(c(x, right))
      if (all(is.finite(h))) {
        return((h[2L] - h[1L]) / step)
      }
    } else if (left > domain[1L]) {
      h <- log_f(c(left, x))
      if (all(is.finite(h))) {
        return((h[2L] - h[1L]) / step)
      }
    }
    step <- step / 2
  }

  .ars_stop("could not compute a finite numerical derivative at x = %.12g.", x)
}

.ars_evaluate_support <- function(log_f, x, domain, derivative_step, concavity_tol) {
  x <- .ars_check_initial_points(x, domain)
  h <- log_f(x)
  if (any(!is.finite(h))) {
    .ars_stop("log density must be finite at all initial/support points.")
  }
  s <- vapply(
    x,
    function(xi) .ars_numeric_derivative_one(log_f, xi, domain, derivative_step),
    numeric(1L)
  )
  if (any(!is.finite(s))) {
    .ars_stop("computed derivative was not finite at one or more support points.")
  }

  support <- list(x = x, h = as.numeric(h), s = as.numeric(s))
  .ars_check_log_concavity(support, concavity_tol)
  support
}

.ars_check_log_concavity <- function(support, concavity_tol) {
  n <- length(support$x)
  if (n >= 2L) {
    slope_increases <- diff(support$s)
    if (any(slope_increases > concavity_tol)) {
      .ars_stop("non-log-concave density detected: log-density slopes increased.")
    }
  }
  if (n >= 3L) {
    for (i in 2L:(n - 1L)) {
      left <- i - 1L
      right <- i + 1L
      lambda <- (support$x[i] - support$x[left]) /
        (support$x[right] - support$x[left])
      chord <- (1 - lambda) * support$h[left] + lambda * support$h[right]
      if (support$h[i] + concavity_tol < chord) {
        .ars_stop("non-log-concave density detected: log density fell below a chord.")
      }
    }
  }
  invisible(TRUE)
}

.ars_tail_step <- function(x, domain) {
  finite_x <- x[is.finite(x)]
  if (length(finite_x) >= 2L) {
    return(max(1, diff(range(finite_x))))
  }
  if (is.finite(domain[1L]) && is.finite(domain[2L])) {
    return(max(1e-3, (domain[2L] - domain[1L]) / 4))
  }
  1
}

.ars_initialize_support <- function(log_f, initial_points, domain, derivative_step,
                                    concavity_tol, max_expansions = 60L) {
  if (is.null(initial_points)) {
    x <- .ars_default_initial_points(domain)
  } else {
    x <- initial_points
  }
  x <- .ars_check_initial_points(x, domain)
  support <- .ars_evaluate_support(log_f, x, domain, derivative_step, concavity_tol)

  if (!is.finite(domain[1L])) {
    step <- .ars_tail_step(support$x, domain)
    expansions <- 0L
    while (support$s[1L] <= 0) {
      expansions <- expansions + 1L
      if (expansions > max_expansions) {
        .ars_stop("could not find a left-tail support point with positive log-density slope.")
      }
      x <- c(support$x[1L] - step, support$x)
      support <- .ars_evaluate_support(log_f, x, domain, derivative_step, concavity_tol)
      step <- step * 2
    }
  }

  if (!is.finite(domain[2L])) {
    step <- .ars_tail_step(support$x, domain)
    expansions <- 0L
    while (support$s[length(support$s)] >= 0) {
      expansions <- expansions + 1L
      if (expansions > max_expansions) {
        .ars_stop("could not find a right-tail support point with negative log-density slope.")
      }
      x <- c(support$x, support$x[length(support$x)] + step)
      support <- .ars_evaluate_support(log_f, x, domain, derivative_step, concavity_tol)
      step <- step * 2
    }
  }

  support
}

.ars_compress_tangents <- function(support, concavity_tol) {
  x <- support$x
  h <- support$h
  s <- support$s
  a <- h - s * x

  keep_x <- x[1L]
  keep_h <- h[1L]
  keep_s <- s[1L]
  keep_a <- a[1L]

  if (length(x) >= 2L) {
    for (i in 2L:length(x)) {
      last <- length(keep_x)
      same_slope <- abs(s[i] - keep_s[last]) <= concavity_tol
      same_intercept <- abs(a[i] - keep_a[last]) <=
        concavity_tol * (1 + abs(a[i]) + abs(keep_a[last]))

      if (same_slope && same_intercept) {
        next
      }
      if (same_slope && !same_intercept) {
        .ars_stop("parallel tangent lines disagree; density may not be log-concave.")
      }

      keep_x <- c(keep_x, x[i])
      keep_h <- c(keep_h, h[i])
      keep_s <- c(keep_s, s[i])
      keep_a <- c(keep_a, a[i])
    }
  }

  list(x = keep_x, h = keep_h, s = keep_s, a = keep_a)
}

.ars_log1mexp <- function(x) {
  ifelse(x < log(0.5), log1p(-exp(x)), log(-expm1(x)))
}

.ars_log_integral <- function(a, b, lower, upper) {
  if (lower >= upper) {
    return(-Inf)
  }

  if (abs(b) < 1e-12) {
    if (!is.finite(lower) || !is.finite(upper)) {
      return(Inf)
    }
    return(a + log(upper - lower))
  }

  if (b > 0) {
    if (!is.finite(upper)) {
      return(Inf)
    }
    if (!is.finite(lower)) {
      return(a + b * upper - log(b))
    }
    return(a + b * upper + .ars_log1mexp(b * (lower - upper)) - log(b))
  }

  if (!is.finite(lower)) {
    return(Inf)
  }
  if (!is.finite(upper)) {
    return(a + b * lower - log(-b))
  }
  a + b * lower + .ars_log1mexp(b * (upper - lower)) - log(-b)
}

.ars_build_hull <- function(support, domain, concavity_tol) {
  .ars_check_log_concavity(support, concavity_tol)
  envelope <- .ars_compress_tangents(support, concavity_tol)
  m <- length(envelope$x)

  if (!is.finite(domain[1L]) && envelope$s[1L] <= 0) {
    .ars_stop("left tail of the envelope is not integrable.")
  }
  if (!is.finite(domain[2L]) && envelope$s[m] >= 0) {
    .ars_stop("right tail of the envelope is not integrable.")
  }

  z <- numeric(m + 1L)
  z[1L] <- domain[1L]
  z[m + 1L] <- domain[2L]
  if (m >= 2L) {
    for (i in seq_len(m - 1L)) {
      denom <- envelope$s[i + 1L] - envelope$s[i]
      if (abs(denom) <= concavity_tol) {
        .ars_stop("could not construct hull because adjacent tangents are parallel.")
      }
      z[i + 1L] <- (envelope$a[i] - envelope$a[i + 1L]) / denom
    }
  }

  if (any(is.na(z)) || any(diff(z) <= -concavity_tol)) {
    .ars_stop("non-log-concave density detected: envelope intersections are not ordered.")
  }
  if (any(diff(z) <= 0)) {
    .ars_stop("could not construct a strictly ordered envelope.")
  }

  log_weights <- numeric(m)
  for (i in seq_len(m)) {
    log_weights[i] <- .ars_log_integral(envelope$a[i], envelope$s[i], z[i], z[i + 1L])
  }
  if (any(is.infinite(log_weights) & log_weights > 0) ||
      all(!is.finite(log_weights))) {
    .ars_stop("envelope has non-finite total mass.")
  }

  list(
    support = support,
    envelope = envelope,
    z = z,
    log_weights = log_weights
  )
}

.ars_sample_log_linear <- function(b, lower, upper) {
  u <- runif(1L)

  if (abs(b) < 1e-12) {
    if (!is.finite(lower) || !is.finite(upper)) {
      .ars_stop("cannot sample a flat envelope over an infinite interval.")
    }
    return(lower + u * (upper - lower))
  }

  if (b > 0) {
    if (!is.finite(upper)) {
      .ars_stop("cannot sample an increasing envelope with infinite upper bound.")
    }
    left_term <- if (is.finite(lower)) exp(b * (lower - upper)) else 0
    return(upper + log(left_term + u * (1 - left_term)) / b)
  }

  if (!is.finite(lower)) {
    .ars_stop("cannot sample a decreasing envelope with infinite lower bound.")
  }
  right_term <- if (is.finite(upper)) exp(b * (upper - lower)) else 0
  lower + log(1 - u * (1 - right_term)) / b
}

.ars_sample_envelope <- function(hull) {
  lw <- hull$log_weights
  probs <- exp(lw - max(lw))
  interval <- sample.int(length(probs), size = 1L, prob = probs)
  lower <- hull$z[interval]
  upper <- hull$z[interval + 1L]
  b <- hull$envelope$s[interval]
  a <- hull$envelope$a[interval]
  x <- .ars_sample_log_linear(b, lower, upper)
  list(x = x, upper = a + b * x, interval = interval)
}

.ars_eval_lower <- function(support, x) {
  m <- length(support$x)
  if (m < 2L) {
    return(-Inf)
  }
  interval <- findInterval(x, support$x)
  if (interval < 1L || interval >= m) {
    return(-Inf)
  }
  x0 <- support$x[interval]
  x1 <- support$x[interval + 1L]
  h0 <- support$h[interval]
  h1 <- support$h[interval + 1L]
  h0 + (h1 - h0) * (x - x0) / (x1 - x0)
}

.ars_add_support <- function(support, x, h, s, concavity_tol) {
  if (any(abs(support$x - x) <= concavity_tol * (1 + abs(x)))) {
    return(support)
  }
  x_new <- c(support$x, x)
  h_new <- c(support$h, h)
  s_new <- c(support$s, s)
  ord <- order(x_new)
  support_new <- list(x = x_new[ord], h = h_new[ord], s = s_new[ord])
  .ars_check_log_concavity(support_new, concavity_tol)
  support_new
}

#' Adaptive rejection sampling for a univariate log-concave density.
#'
#' @param target A vectorized density function, a log-density function when
#'   log_density is TRUE, or an expression involving x.
#' @param n Number of samples to generate.
#' @param domain Numeric vector c(lower, upper). Bounds may be infinite.
#' @param initial_points Finite support points strictly inside the domain.
#' @param log_density TRUE when target returns log-density values.
#' @param ... Additional arguments passed to target when target is a function.
#' @return A numeric vector of samples.
ars <- function(target, n, domain = c(-Inf, Inf), initial_points = NULL,
                log_density = FALSE, max_points = 200L,
                max_iterations = NULL, derivative_step = NULL,
                concavity_tol = 1e-5, envelope_tol = 1e-5,
                seed = NULL, ...) {
  n <- .ars_check_count(n)
  domain <- .ars_check_domain(domain)
  if (!is.logical(log_density) || length(log_density) != 1L || is.na(log_density)) {
    .ars_stop("log_density must be TRUE or FALSE.")
  }
  if (!is.numeric(max_points) || length(max_points) != 1L ||
      !is.finite(max_points) || max_points < 1L) {
    .ars_stop("max_points must be a positive finite number.")
  }
  max_points <- as.integer(max_points)
  if (is.null(max_iterations)) {
    max_iterations <- max(10000L, 100L * n)
  }
  if (!is.numeric(max_iterations) || length(max_iterations) != 1L ||
      !is.finite(max_iterations) || max_iterations < n) {
    .ars_stop("max_iterations must be a finite number at least as large as n.")
  }
  max_iterations <- as.integer(max_iterations)
  if (!is.numeric(concavity_tol) || length(concavity_tol) != 1L ||
      !is.finite(concavity_tol) || concavity_tol <= 0) {
    .ars_stop("concavity_tol must be a positive finite number.")
  }
  if (!is.numeric(envelope_tol) || length(envelope_tol) != 1L ||
      !is.finite(envelope_tol) || envelope_tol <= 0) {
    .ars_stop("envelope_tol must be a positive finite number.")
  }
  if (!is.null(seed)) {
    set.seed(seed)
  }

  log_f <- .ars_make_log_density(
    substitute(target),
    parent.frame(),
    log_density,
    list(...)
  )

  support <- .ars_initialize_support(
    log_f,
    initial_points,
    domain,
    derivative_step,
    concavity_tol
  )
  hull <- .ars_build_hull(support, domain, concavity_tol)

  samples <- numeric(n)
  accepted <- 0L
  iterations <- 0L

  while (accepted < n && iterations < max_iterations) {
    iterations <- iterations + 1L
    proposal <- .ars_sample_envelope(hull)
    x <- proposal$x
    upper <- proposal$upper
    log_u <- log(runif(1L))

    lower <- .ars_eval_lower(hull$support, x)
    if (is.finite(lower) && log_u <= lower - upper) {
      accepted <- accepted + 1L
      samples[accepted] <- x
      next
    }

    h_x <- log_f(x)
    if (length(h_x) != 1L || !is.finite(h_x)) {
      .ars_stop("log density was not finite at proposed point x = %.12g.", x)
    }
    if (h_x > upper + envelope_tol) {
      .ars_stop(
        "non-log-concave density detected: log density exceeded tangent envelope at x = %.12g.",
        x
      )
    }

    if (log_u <= h_x - upper) {
      accepted <- accepted + 1L
      samples[accepted] <- x
    } else if (length(hull$support$x) < max_points) {
      s_x <- .ars_numeric_derivative_one(log_f, x, domain, derivative_step)
      support <- .ars_add_support(hull$support, x, h_x, s_x, concavity_tol)
      hull <- .ars_build_hull(support, domain, concavity_tol)
    }
  }

  if (accepted < n) {
    .ars_stop(
      "sampling stopped after %d iterations with only %d accepted samples.",
      iterations,
      accepted
    )
  }

  attr(samples, "iterations") <- iterations
  attr(samples, "support_points") <- length(hull$support$x)
  samples
}

.ars_test_line <- function(name, passed, values = numeric(0L), details = "") {
  if (length(values) > 0L) {
    mean_value <- mean(values)
    sd_value <- stats::sd(values)
  } else {
    mean_value <- NA_real_
    sd_value <- NA_real_
  }
  cat(sprintf(
    "%s: %s mean=%.6f sd=%.6f%s\n",
    name,
    if (isTRUE(passed)) "PASS" else "FAIL",
    mean_value,
    sd_value,
    if (nzchar(details)) paste0(" ", details) else ""
  ))
  isTRUE(passed)
}

.ars_run_test <- function(name, expr, values = NULL, details = "") {
  result <- try(force(expr), silent = TRUE)
  if (inherits(result, "try-error")) {
    .ars_test_line(name, FALSE, numeric(0L), paste("error=", conditionMessage(attr(result, "condition"))))
    return(FALSE)
  }
  vals <- if (is.null(values)) {
    if (is.numeric(result)) result else numeric(0L)
  } else {
    values
  }
  .ars_test_line(name, isTRUE(result$passed %||% result), vals, details)
}

`%||%` <- function(a, b) {
  if (is.null(a)) b else a
}

#' Run formal tests for the ARS implementation.
#'
#' The output uses "TEST_NAME: PASS" or "TEST_NAME: FAIL" and includes mean
#' and standard deviation fields for readability. The normal sampling test
#' writes /app/normal_samples.txt.
test <- function() {
  results <- logical(0L)

  normal_samples <- try(
    ars(
      dnorm,
      n = 4000,
      domain = c(-Inf, Inf),
      initial_points = c(-2, 0, 2),
      seed = 101
    ),
    silent = TRUE
  )
  if (inherits(normal_samples, "try-error")) {
    results["NORMAL_SAMPLING"] <- .ars_test_line(
      "NORMAL_SAMPLING",
      FALSE,
      numeric(0L),
      paste("error=", conditionMessage(attr(normal_samples, "condition")))
    )
  } else {
    write.table(
      normal_samples,
      file = "/app/normal_samples.txt",
      row.names = FALSE,
      col.names = FALSE
    )
    ks_p <- suppressWarnings(stats::ks.test(normal_samples, "pnorm")$p.value)
    passed <- abs(mean(normal_samples)) < 0.07 &&
      abs(stats::sd(normal_samples) - 1) < 0.07 &&
      ks_p > 0.001
    results["NORMAL_SAMPLING"] <- .ars_test_line(
      "NORMAL_SAMPLING",
      passed,
      normal_samples,
      sprintf("ks_p=%.6f expected_mean=0 expected_sd=1", ks_p)
    )
  }

  exponential_samples <- try(
    ars(
      dexp,
      n = 4000,
      domain = c(0, Inf),
      initial_points = c(0.25, 1, 3),
      seed = 202,
      rate = 2
    ),
    silent = TRUE
  )
  if (inherits(exponential_samples, "try-error")) {
    results["EXPONENTIAL_SAMPLING"] <- .ars_test_line(
      "EXPONENTIAL_SAMPLING",
      FALSE,
      numeric(0L),
      paste("error=", conditionMessage(attr(exponential_samples, "condition")))
    )
  } else {
    ks_p <- suppressWarnings(stats::ks.test(exponential_samples, "pexp", rate = 2)$p.value)
    passed <- abs(mean(exponential_samples) - 0.5) < 0.04 &&
      abs(stats::sd(exponential_samples) - 0.5) < 0.05 &&
      ks_p > 0.001
    results["EXPONENTIAL_SAMPLING"] <- .ars_test_line(
      "EXPONENTIAL_SAMPLING",
      passed,
      exponential_samples,
      sprintf("ks_p=%.6f expected_mean=0.5 expected_sd=0.5", ks_p)
    )
  }

  log_integral <- .ars_log_integral(log(2), -2, 0, Inf)
  results["ENVELOPE_INTEGRAL"] <- .ars_test_line(
    "ENVELOPE_INTEGRAL",
    is.finite(log_integral) && abs(log_integral) < 1e-10,
    c(log_integral),
    "expected_log_integral=0"
  )

  support <- try(
    .ars_evaluate_support(
      function(x) stats::dnorm(x, log = TRUE),
      c(-2, 0, 2),
      c(-Inf, Inf),
      NULL,
      1e-5
    ),
    silent = TRUE
  )
  if (inherits(support, "try-error")) {
    results["HULL_NORMAL"] <- .ars_test_line(
      "HULL_NORMAL",
      FALSE,
      numeric(0L),
      paste("error=", conditionMessage(attr(support, "condition")))
    )
  } else {
    hull <- .ars_build_hull(support, c(-Inf, Inf), 1e-5)
    passed <- all(diff(hull$z) > 0) &&
      hull$z[1L] == -Inf &&
      hull$z[length(hull$z)] == Inf
    results["HULL_NORMAL"] <- .ars_test_line(
      "HULL_NORMAL",
      passed,
      hull$z[is.finite(hull$z)],
      sprintf("support_points=%d", length(support$x))
    )
  }

  invalid_n_error <- inherits(
    try(ars(dnorm, n = -5, initial_points = c(-1, 0, 1)), silent = TRUE),
    "try-error"
  )
  results["INPUT_VALIDATION"] <- .ars_test_line(
    "INPUT_VALIDATION",
    invalid_n_error,
    numeric(0L),
    "negative n rejected"
  )

  invalid_domain_error <- inherits(
    try(ars(dnorm, n = 10, domain = c(1, 1), initial_points = 0), silent = TRUE),
    "try-error"
  )
  results["DOMAIN_VALIDATION"] <- .ars_test_line(
    "DOMAIN_VALIDATION",
    invalid_domain_error,
    numeric(0L),
    "invalid domain rejected"
  )

  mixture_density <- function(x) {
    0.5 * stats::dnorm(x, mean = -2, sd = 0.4) +
      0.5 * stats::dnorm(x, mean = 2, sd = 0.4)
  }
  non_log_concave_error <- inherits(
    try(
      ars(
        mixture_density,
        n = 10,
        domain = c(-Inf, Inf),
        initial_points = c(-2, 0, 2),
        seed = 303
      ),
      silent = TRUE
    ),
    "try-error"
  )
  results["NON_LOG_CONCAVE"] <- .ars_test_line(
    "NON_LOG_CONCAVE",
    non_log_concave_error,
    numeric(0L),
    "bimodal mixture rejected"
  )

  invisible(results)
}

